cartGetIdDefault = (
  requestHeaders: CrossRuntimeRequest['headers'],
) => {
  const cookies = parse(getHeaderValue(requestHeaders, 'Cookie') || '');
  return () => {
    return cookies.cart ? `gid://shopify/Cart/${cookies.cart}` : undefined;
  };
}

src/cart/cartSetIdDefault.ts.value:
cartSetIdDefault = (cookieOptions?: CookieOptions) => {
  return (cartId: string) => {
    const headers = new Headers();
    headers.append(
      'Set-Cookie',
      stringify('cart', cartId.split('/').pop() || '', {
        path: '/',
        ...cookieOptions,
      }),
    );
    return headers;
  };
}

