      errors: StorefrontApiErrors;
    }>(
      CART_DELIVERY_ADDRESSES_ADD_MUTATION(options.cartFragment, {
        includeVisitorConsent,
      }),
      {
        variables: {
          cartId: options.getCartId(),
          addresses,
          ...optionalParams,
        },
      },
    );

    return formatAPIResult(cartDeliveryAddressesAdd, errors);
  };
}

