        ...metafield,
        parsedValue,
      } as ReturnGeneric;
    }

    case 'dimension':
    case 'json':
    case 'rating':
    case 'volume':
    case 'weight':
    case 'rich_text_field':
    case 'list.color':
    case 'list.dimension':
    case 'list.number_integer':
    case 'list.number_decimal':
    case 'list.rating':
    case 'list.single_line_text_field':
    case 'list.url':
    case 'list.volume':
